class SpatialGrid:
    """Spatial partitioning for efficient proximity queries."""

    def __init__(self, world_size: float, cell_size: float):
        self.world_size = world_size
        self.cell_size = cell_size
        self.grid_size = int(math.ceil(world_size / cell_size))
        self.cells: Dict[Tuple[int, int], Set[str]] = {}

    def _get_cell(self, pos: Vector2) -> Tuple[int, int]:
        cx = int(pos.x / self.cell_size) % self.grid_size
        cy = int(pos.y / self.cell_size) % self.grid_size
        return (cx, cy)

    def update_player(self, player_id: str, old_pos: Optional[Vector2], new_pos: Vector2):
        if old_pos:
            old_cell = self._get_cell(old_pos)
            if old_cell in self.cells:
                self.cells[old_cell].discard(player_id)
        new_cell = self._get_cell(new_pos)
        if new_cell not in self.cells:
            self.cells[new_cell] = set()
        self.cells[new_cell].add(player_id)

    def remove_player(self, player_id: str, pos: Vector2):
        cell = self._get_cell(pos)
        if cell in self.cells:
            self.cells[cell].discard(player_id)

    def get_nearby_players(self, pos: Vector2, radius: float) -> Set[str]:
        """Get all player IDs within radius."""
        result = set()
        cells_to_check = int(math.ceil(radius / self.cell_size)) + 1
        center_cell = self._get_cell(pos)

        for dx in range(-cells_to_check, cells_to_check + 1):
            for dy in range(-cells_to_check, cells_to_check + 1):
                cell = (
                    (center_cell[0] + dx) % self.grid_size,
                    (center_cell[1] + dy) % self.grid_size,
                )
                if cell in self.cells:
                    result.update(self.cells[cell])
        return result


class LineOfSightChecker:
    """Server-side line of sight checking to prevent wallhack."""

    def __init__(self, obstacles: List[Obstacle]):
        self.obstacles = obstacles

    def _line_intersects_aabb(self, p1: Vector2, p2: Vector2, aabb: AABB) -> bool:
        """Check if line segment from p1 to p2 intersects an AABB."""
        dx = p2.x - p1.x
        dy = p2.y - p1.y

        t_min = 0.0
        t_max = 1.0

        if abs(dx) < 1e-10:
            if p1.x < aabb.min_x or p1.x > aabb.max_x:
                return False
        else:
            t1 = (aabb.min_x - p1.x) / dx
            t2 = (aabb.max_x - p1.x) / dx
            if t1 > t2:
                t1, t2 = t2, t1
            t_min = max(t_min, t1)
            t_max = min(t_max, t2)
            if t_min > t_max:
                return False

        if abs(dy) < 1e-10:
            if p1.y < aabb.min_y or p1.y > aabb.max_y:
                return False
        else:
            t1 = (aabb.min_y - p1.y) / dy
            t2 = (aabb.max_y - p1.y) / dy
            if t1 > t2:
                t1, t2 = t2, t1
            t_min = max(t_min, t1)
            t_max = min(t_max, t2)
            if t_min > t_max:
                return False

        return True

    def has_line_of_sight(self, from_pos: Vector2, to_pos: Vector2) -> bool:
        """Check if there's a clear line of sight between two positions."""
        for obstacle in self.obstacles:
            if obstacle.blocks_sight:
                if self._line_intersects_aabb(from_pos, to_pos, obstacle.bounds):
                    return False
        return True


class BattleRoyaleServer:
    """
    Secure Battle Royale game server.

    SECURITY: Server-side visibility filtering prevents wallhack exploits.
    Only players that are within view distance AND have line of sight
    are included in the state sent to each client.
    """

    # Game constants
    WORLD_SIZE = 4000.0
    TICK_RATE = 20  # Server ticks per second
    MAX_PLAYERS = 100
    VIEW_DISTANCE = 200.0  # Maximum distance a player can see
    AUDIO_DISTANCE = 300.0  # Distance for audio cues (direction only, no position)
    MOVEMENT_SPEED = 5.0
    ZONE_TICK_INTERVAL = 1.0
    SPATIAL_CELL_SIZE = 100.0

    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.loot_items: Dict[str, LootItem] = {}
        self.obstacles: List[Obstacle] = []
        self.game_phase = GamePhase.LOBBY
        self.tick_count = 0
        self.zone = Zone(
            center=Vector2(self.WORLD_SIZE / 2, self.WORLD_SIZE / 2),
            current_radius=self.WORLD_SIZE / 2,
            target_radius=self.WORLD_SIZE / 2,
            shrink_rate=0.5,
            damage_per_tick=5,
        )
        self.spatial_grid = SpatialGrid(self.WORLD_SIZE, self.SPATIAL_CELL_SIZE)
        self.los_checker: Optional[LineOfSightChecker] = None
        self.kill_feed: List[dict] = []
        self.game_start_time: Optional[float] = None
        self._running = False

        self._generate_map()

    def _generate_map(self):
        """Generate map obstacles."""
        import random
        random.seed(42)  # Deterministic map

        # Generate buildings
        for i in range(50):
            x = random.uniform(100, self.WORLD_SIZE - 100)
            y = random.uniform(100, self.WORLD_SIZE - 100)
            w = random.uniform(20, 60)
            h = random.uniform(20, 60)
            self.obstacles.append(Obstacle(
                obstacle_id=f"building_{i}",
                obstacle_type=ObstacleType.BUILDING,
                bounds=AABB(x, y, x + w, y + h),
                blocks_sight=True,
            ))

        # Generate walls
        for i in range(100):
            x = random.uniform(50, self.WORLD_SIZE - 50)
            y = random.uniform(50, self.WORLD_SIZE - 50)
            if random.random() > 0.5:
                w = random.uniform(30, 80)
                h = 2.0
            else:
                w = 2.0
                h = random.uniform(30, 80)
            self.obstacles.append(Obstacle(
                obstacle_id=f"wall_{i}",
                obstacle_type=ObstacleType.WALL,
                bounds=AABB(x, y, x + w, y + h),
                blocks_sight=True,
            ))

        # Generate terrain (rocks, etc.) - some don't block sight
        for i in range(30):
            x = random.uniform(50, self.WORLD_SIZE - 50)
            y = random.uniform(50, self.WORLD_SIZE - 50)
            r = random.uniform(5, 15)
            self.obstacles.append(Obstacle(
                obstacle_id=f"terrain_{i}",
                obstacle_type=ObstacleType.TERRAIN,
                bounds=AABB(x - r, y - r, x + r, y + r),
                blocks_sight=random.random() > 0.3,
            ))

        self.los_checker = LineOfSightChecker(self.obstacles)

        # Generate loot
        for i in range(200):
            x = random.uniform(50, self.WORLD_SIZE - 50)
            y = random.uniform(50, self.WORLD_SIZE - 50)
            item_type = random.choice(["ammo", "health", "shield", "weapon_ar", "weapon_sniper", "weapon_shotgun"])
            value = {"ammo": 30, "health": 25, "shield": 25, "weapon_ar": 1, "weapon_sniper": 1, "weapon_shotgun": 1}[item_type]
            self.loot_items[f"loot_{i}"] = LootItem(
                item_id=f"loot_{i}",
                position=Vector2(x, y),
                item_type=item_type,
                value=value,
            )

    def _generate_auth_token(self) -> str:
        return secrets.token_hex(32)

    async def handle_connection(self, websocket: websockets.WebSocketServerProtocol, path: str):
        player_id = None
        try:
            # Wait for authentication message
            auth_msg = await asyncio.wait_for(websocket.recv(), timeout=10.0)
            auth_data = json.loads(auth_msg)

            if auth_data.get("type") != "auth":
                await websocket.send(json.dumps({"type": "error", "message": "Expected auth message"}))
                return

            username = auth_data.get("username", "").strip()
            if not username or len(username) > 20:
                await websocket.send(json.dumps({"type": "error", "message": "Invalid username"}))
                return

            if len(self.players) >= self.MAX_PLAYERS:
                await websocket.send(json.dumps({"type": "error", "message": "Server full"}))
                return

            player_id = str(uuid.uuid4())
            auth_token = self._generate_auth_token()

            import random
            spawn_x = random.uniform(100, self.WORLD_SIZE - 100)
            spawn_y = random.uniform(100, self.WORLD_SIZE - 100)

            player = Player(
                player_id=player_id,
                username=username,
                position=Vector2(spawn_x, spawn_y),
                auth_token=auth_token,
            )

            self.players[player_id] = player
            self.connections[player_id] = websocket
            self.spatial_grid.update_player(player_id, None, player.position)

            # Send auth success with map data (static, same for everyone)
            await websocket.send(json.dumps({
                "type": "auth_success",
                "player_id": player_id,
                "auth_token": auth_token,
                "map": {
                    "world_size": self.WORLD_SIZE,
                    "obstacles": [o.to_dict() for o in self.obstacles],
                },
            }))

            print(f"Player {username} ({player_id}) connected. Total: {len(self.players)}")

            # Handle messages
            async for message in websocket:
                try:
                    data = json.loads(message)
                    await self._handle_player_message(player_id, data)
                except json.JSONDecodeError:
                    continue
                except Exception as e:
                    print(f"Error handling message from {player_id}: {e}")

        except asyncio.TimeoutError:
            pass
        except websockets.exceptions.ConnectionClosed:
            pass
        except Exception as e:
            print(f"Connection error: {e}")
        finally:
            if player_id and player_id in self.players:
                self._disconnect_player(player_id)

    def _disconnect_player(self, player_id: str):
        player = self.players.get(player_id)
        if player:
            player.connected = False
            self.spatial_grid.remove_player(player_id, player.position)
            print(f"Player {player.username} ({player_id}) disconnected. Total: {len(self.players) - 1}")
        self.connections.pop(player_id, None)
        self.players.pop(player_id, None)

    async def _handle_player_message(self, player_id: str, data: dict):
        msg_type = data.get("type")
        player = self.players.get(player_id)
        if not player or not player.alive:
            return

        if msg_type == "move":
            await self._handle_move(player, data)
        elif msg_type == "shoot":
            await self._handle_shoot(player, data)
        elif msg_type == "pickup":
            await self._handle_pickup(player, data)
        elif msg_type == "ping":
            ws = self.connections.get(player_id)
            if ws:
                await ws.send(json.dumps({
                    "type": "pong",
                    "server_time": time.time(),
                    "client_time": data.get("client_time", 0),
                }))

    async def _handle_move(self, player: Player, data: dict):
        dx = data.get("dx", 0)
        dy = data.get("dy", 0)
        heading = data.get("heading", player.heading)
        input_seq = data.get("input_seq", 0)

        # Validate and clamp input
        dx = max(-1.0, min(1.0, float(dx)))
        dy = max(-1.0, min(1.0, float(dy)))

        # Normalize diagonal movement
        magnitude = math.sqrt(dx * dx + dy * dy)
        if magnitude > 1.0:
            dx /= magnitude
            dy /= magnitude

        old_pos = Vector2(player.position.x, player.position.y)
        new_x = player.position.x + dx * self.MOVEMENT_SPEED
        new_y = player.position.y + dy * self.MOVEMENT_SPEED

        # Clamp to world bounds
        new_x = max(0, min(self.WORLD_SIZE, new_x))
        new_y = max(0, min(self.WORLD_SIZE, new_y))

        # Collision check with obstacles
        player_radius = 2.0
        can_move = True
        for obstacle in self.obstacles:
            b = obstacle.bounds
            closest_x = max(b.min_x, min(new_x, b.max_x))
            closest_y = max(b.min_y, min(new_y, b.max_y))
            dist = math.sqrt((new_x - closest_x) ** 2 + (new_y - closest_y) ** 2)
            if dist < player_radius:
                can_move = False
                break

        if can_move:
            player.position.x = new_x
            player.position.y = new_y
            self.spatial_grid.update_player(player.player_id, old_pos, player.position)

        player.heading = float(heading)
        player.speed = magnitude * self.MOVEMENT_SPEED
        player.last_input_seq = input_seq

    async def _handle_shoot(self, player: Player, data: dict):
        if player.ammo <= 0:
            return

        target_x = data.get("target_x", 0)
        target_y = data.get("target_y", 0)

        dx = target_x - player.position.x
        dy = target_y - player.position.y
        dist = math.sqrt(dx * dx + dy * dy)
        if dist < 0.01:
            return

        # Normalize
        dx /= dist
        dy /= dist

        bullet_speed = 50.0
        damage_map = {"pistol": 15, "weapon_ar": 20, "weapon_sniper": 50, "weapon_shotgun": 30}
        damage = damage_map.get(player.weapon, 15)

        projectile = Projectile(
            projectile_id=str(uuid.uuid4()),
            owner_id=player.player_id,
            position=Vector2(player.position.x, player.position.y),
            velocity=Vector2(dx * bullet_speed, dy * bullet_speed),
            damage=damage,
            created_at=time.time(),
        )
        self.projectiles[projectile.projectile_id] = projectile
        player.ammo -= 1

    async def _handle_pickup(self, player: Player, data: dict):
        item_id = data.get("item_id")
        if not item_id or item_id not in self.loot_items:
            return

        item = self.loot_items[item_id]
        if player.position.distance_to(item.position) > 10.0:
            return

        if item.item_type == "ammo":
            player.ammo += item.value
        elif item.item_type == "health":
            player.health = min(100, player.health + item.value)
        elif item.item_type == "shield":
            player.shield = min(100, player.shield + item.value)
        elif item.item_type.startswith("weapon_"):
            player.weapon = item.item_type
            player.ammo = 30

        del self.loot_items[item_id]

    def _get_visible_players_for(self, viewer: Player) -> Tuple[List[dict], List[dict]]:
        """
        SERVER-SIDE VISIBILITY FILTERING (Anti-wallhack).

        Returns (visible_players, audible_players) for the given viewer.
        Only players within VIEW_DISTANCE with clear line of sight are 'visible'.
        Players within AUDIO_DISTANCE but not visible get minimal 'audible' info.
        Players beyond AUDIO_DISTANCE get NO information at all.
        """
        visible = []
        audible = []

        # Use spatial grid for efficient proximity query
        nearby_ids = self.spatial_grid.get_nearby_players(
            viewer.position, self.AUDIO_DISTANCE
        )

        for pid in nearby_ids:
            if pid == viewer.player_id:
                continue

            other = self.players.get(pid)
            if not other or not other.connected:
                continue

            # Dead players: show death marker if within view distance and LOS
            if not other.alive:
                dist = viewer.position.distance_to(other.position)
                if dist <= self.VIEW_DISTANCE:
                    if self.los_checker and self.los_checker.has_line_of_sight(
                        viewer.position, other.position
                    ):
                        visible.append(other.to_dict_dead())
                continue

            dist = viewer.position.distance_to(other.position)

            # Teammates always visible (if team mode)
            if viewer.team_id and other.team_id == viewer.team_id:
                visible.append(other.to_dict_visible())
                continue

            # Within view distance - check line of sight
            if dist <= self.VIEW_DISTANCE:
                if self.los_checker and self.los_checker.has_line_of_sight(
                    viewer.position, other.position
                ):
                    visible.append(other.to_dict_visible())
                else:
                    # Behind wall but close - audio cue only
                    if dist <= self.AUDIO_DISTANCE:
                        audible.append(other.to_dict_audible())
            elif dist <= self.AUDIO_DISTANCE:
                # Beyond view but within audio range - direction hint only
                audible.append(other.to_dict_audible())

        return visible, audible

    def _get_visible_projectiles_for(self, viewer: Player) -> List[dict]:
        """Only return projectiles within view distance and LOS."""
        visible = []
        for proj in self.projectiles.values():
            dist = viewer.position.distance_to(proj.position)
            if dist <= self.VIEW_DISTANCE:
                if self.los_checker and self.los_checker.has_line_of_sight(
                    viewer.position, proj.position
                ):
                    visible.append(proj.to_dict())
        return visible

    def _get_visible_loot_for(self, viewer: Player) -> List[dict]:
        """Only return loot within view distance and LOS."""
        visible = []
        for item in self.loot_items.values():
            dist = viewer.position.distance_to(item.position)
            if dist <= self.VIEW_DISTANCE:
                if self.los_checker and self.los_checker.has_line_of_sight(
                    viewer.position, item.position
                ):
                    visible.append(item.to_dict())
        return visible

    def _update_projectiles(self, dt: float):
        """Update projectile positions and check hits."""
        to_remove = []
        current_time = time.time()

        for proj_id, proj in self.projectiles.items():
            # Check TTL
            if current_time - proj.created_at > proj.ttl:
                to_remove.append(proj_id)
                continue

            # Move projectile
            proj.position.x += proj.velocity.x * dt
            proj.position.y += proj.velocity.y * dt

            # Check world bounds
            if (proj.position.x < 0 or proj.position.x > self.WORLD_SIZE or
                    proj.position.y < 0 or proj.position.y > self.WORLD_SIZE):
                to_remove.append(proj_id)
                continue

            # Check obstacle collision
            hit_obstacle = False
            for obstacle in self.obstacles:
                b = obstacle.bounds
                if b.min_x <= proj.position.x <= b.max_x and b.min_y <= proj.position.y <= b.max_y:
                    hit_obstacle = True
                    break
            if hit_obstacle:
                to_remove.append(proj_id)
                continue

            # Check player hits
            hit_player = False
            for pid, player in self.players.items():
                if pid == proj.owner_id or not player.alive:
                    continue
                if player.position.distance_to(proj.position) < 3.0:
                    # Hit!
                    self._apply_damage(player, proj.damage, proj.owner_id)
                    hit_player = True
                    break
            if hit_player:
                to_remove.append(proj_id)

        for proj_id in to_remove:
            self.projectiles.pop(proj_id, None)

    def _apply_damage(self, target: Player, damage: int, attacker_id: str):
        """Apply damage to a player."""
        remaining_damage = damage

        # Shield absorbs first
        if target.shield > 0:
            shield_damage = min(target.shield, remaining_damage)
            target.shield -= shield_damage
            remaining_damage -= shield_damage

        target.health -= remaining_damage

        if target.health <= 0:
            target.health = 0
            target.alive = False
            attacker = self.players.get(attacker_id)
            if attacker:
                attacker.kills += 1

            kill_entry = {
                "killer": attacker.username if attacker else "Unknown",
                "victim": target.username,
                "weapon": attacker.weapon if attacker else "unknown",
                "timestamp": time.time(),
            }
            self.kill_feed.append(kill_entry)
            # Keep only last 10 kills
            if len(self.kill_feed) > 10:
                self.kill_feed = self.kill_feed[-10:]

    def _update_zone(self, dt: float):
        """Update the zone/circle."""
        if self.game_phase not in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            return

        if self.zone.current_radius > self.zone.target_radius:
            self.zone.current_radius = max(
                self.zone.target_radius,
                self.zone.current_radius - self.zone.shrink_rate * dt,
            )

        # Damage players outside zone
        for player in self.players.values():
            if player.alive and not self.zone.is_inside(player.position):
                self._apply_damage(player, self.zone.damage_per_tick, "zone")

    def _check_game_end(self):
        """Check if the game should end."""
        alive_players = [p for p in self.players.values() if p.alive]
        if len(alive_players) <= 1 and self.game_phase == GamePhase.PLAYING:
            self.game_phase = GamePhase.ENDED

    async def _build_and_send_state(self):
        """
        Build per-player game state with SERVER-SIDE visibility filtering.

        SECURITY: Each player only receives information about entities they
        can actually see. This prevents wallhack cheats because the client
        never receives position data for hidden players.
        """
        alive_count = sum(1 for p in self.players.values() if p.alive)

        # Recent kill feed entries (public info)
        recent_kills = self.kill_feed[-5:] if self.kill_feed else []

        for player_id, ws in list(self.connections.items()):
            player = self.players.get(player_id)
            if not player:
                continue

            try:
                if player.alive:
                    # SERVER-SIDE FILTERING: Only visible players are sent
                    visible_players, audible_players = self._get_visible_players_for(player)
                    visible_projectiles = self._get_visible_projectiles_for(player)
                    visible_loot = self._get_visible_loot_for(player)

                    state = {
                        "type": "game_state",
                        "tick": self.tick_count,
                        "server_time": time.time(),
                        "phase": self.game_phase.value,
                        "alive_count": alive_count,
                        "self": player.to_dict_self(),
                        "visible_players": visible_players,
                        "audible_players": audible_players,
                        "projectiles": visible_projectiles,
                        "loot": visible_loot,
                        "zone": self.zone.to_dict(),
                        "kill_feed": recent_kills,
                        "last_input_seq": player.last_input_seq,
                    }
                else:
                    # Dead players get spectator view - limited to killer or random alive player
                    state = {
                        "type": "game_state",
                        "tick": self.tick_count,
                        "server_time": time.time(),
                        "phase": self.game_phase.value,
                        "alive_count": alive_count,
                        "self": player.to_dict_self(),
                        "visible_players": [],
                        "audible_players": [],
                        "projectiles": [],
                        "loot": [],
                        "zone": self.zone.to_dict(),
                        "kill_feed": recent_kills,
                        "spectating": True,
                    }

                await ws.send(json.dumps(state))

            except websockets.exceptions.ConnectionClosed:
                self._disconnect_player(player_id)
            except Exception as e:
                print(f"Error sending state to {player_id}: {e}")

    async def game_loop(self):
        """Main game loop running at TICK_RATE."""
        self._running = True
        tick_duration = 1.0 / self.TICK_RATE

        # Start game after a delay
        if self.game_phase == GamePhase.LOBBY:
            self.game_phase = GamePhase.PLAYING
            self.game_start_time = time.time()

        print(f"Game loop started at {self.TICK_RATE} ticks/sec")

        while self._running:
            tick_start = time.time()

            # Update game state
            self._update_projectiles(tick_duration)
            self._update_zone(tick_duration)
            self._check_game_end()

            # Zone shrink phases
            if self.game_start_time:
                elapsed = time.time() - self.game_start_time
                if elapsed > 120 and self.zone.target_radius > 500:
                    self.zone.target_radius = 500
                    self.zone.damage_per_tick = 10
                elif elapsed > 240 and self.zone.target_radius > 200:
                    self.zone.target_radius = 200
                    self.zone.damage_per_tick = 20
                    self.game_phase = GamePhase.FINAL_CIRCLE
                elif elapsed > 360 and self.zone.target_radius > 50:
                    self.zone.target_radius = 50
                    self.zone.damage_per_tick = 50

            # Send state to all players (with per-player visibility filtering)
            await self._build_and_send_state()

            self.tick_count += 1

            # Sleep to maintain tick rate
            elapsed = time.time() - tick_start
            sleep_time = max(0, tick_duration - elapsed)
            if sleep_time > 0:
                await asyncio.sleep(sleep_time)

            if self.game_phase == GamePhase.ENDED:
                await self._handle_game_end()
                break

    async def _handle_game_end(self):
        """Handle end of game."""
        alive_players = [p for p in self.players.values() if p.alive]
        winner = alive_players[0] if alive_players else None

        end_msg = json.dumps({
            "type": "game_over",
            "winner": winner.to_dict_full() if winner else None,
            "stats": {
                "total_players": len(self.players),
                "game_duration": time.time() - (self.game_start_time or time.time()),
            },
        })

        for ws in self.connections.values():
            try:
                await ws.send(end_msg)
            except Exception:
                pass

        self._running = False

    async def start(self, host: str = "0.0.0.0", port: int = 8765):
        """Start the game server."""
        print(f"Starting Battle Royale server on {host}:{port}")
        print(f"Security: Server-side visibility filtering ENABLED")
        print(f"  - View distance: {self.VIEW_DISTANCE}")
        print(f"  - Audio distance: {self.AUDIO_DISTANCE}")
        print(f"  - Line of sight checking: ENABLED")
        print(f"  - Per-player state filtering: ENABLED")

        server = await websockets.serve(
            self.handle_connection,
            host,
            port,
            max_size=2 ** 16,
            ping_interval=20,
            ping_timeout=30,
        )

        # Start game loop
        game_task = asyncio.create_task(self.game_loop())

        await server.wait_closed()
        self._running = False
        game_task.cancel()


async def main():
    server = BattleRoyaleServer()
    await server.start()


if __name__ == "__main__":
    asyncio.run(main())